            >
              <Text style={styles.manualEntryText}>Enter Barcode Manually</Text>
            </TouchableOpacity>
          </View>
        </View>
      </CameraView>

      {loading && (
        <View style={styles.loadingOverlay}>
          <ActivityIndicator size="large" color={COLORS.primary} />
          <Text style={styles.loadingText}>Searching for product...</Text>
        </View>
      )}

